"use strict";(globalThis.webpackChunkdocs_site=globalThis.webpackChunkdocs_site||[]).push([[208],{9826(e){e.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"docsSidebar":[{"type":"link","href":"/pychron/docs/intro","label":"Introduction","docId":"intro","unlisted":false},{"type":"category","label":"Getting Started","collapsible":true,"collapsed":false,"items":[{"type":"link","href":"/pychron/docs/getting-started/installation","label":"Installation","docId":"getting-started/installation","unlisted":false},{"type":"link","href":"/pychron/docs/getting-started/quick-start","label":"Quick Start","docId":"getting-started/quick-start","unlisted":false},{"type":"link","href":"/pychron/docs/getting-started/experiment-workflow","label":"First Experiment","docId":"getting-started/experiment-workflow","unlisted":false}]},{"type":"category","label":"Hardware","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/pychron/docs/hardware/overview","label":"Overview","docId":"hardware/overview","unlisted":false},{"type":"link","href":"/pychron/docs/hardware/compatibility-matrix","label":"Compatibility Matrix","docId":"hardware/compatibility-matrix","unlisted":false}]},{"type":"category","label":"DVC","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/pychron/docs/dvc/setup-guide","label":"Setup Guide","docId":"dvc/setup-guide","unlisted":false},{"type":"link","href":"/pychron/docs/dvc/first-run","label":"First-Run Setup","docId":"dvc/first-run","unlisted":false},{"type":"link","href":"/pychron/docs/dvc/configuration","label":"Configuration","docId":"dvc/configuration","unlisted":false},{"type":"link","href":"/pychron/docs/dvc/failure-modes","label":"Failure Modes","docId":"dvc/failure-modes","unlisted":false},{"type":"link","href":"/pychron/docs/dvc/offline-mode","label":"Offline Mode","docId":"dvc/offline-mode","unlisted":false}],"href":"/pychron/docs/dvc/setup-guide"},{"type":"category","label":"Migration","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/pychron/docs/migration/massspec-overview","label":"Overview","docId":"migration/massspec-overview","unlisted":false},{"type":"link","href":"/pychron/docs/migration/massspec-migration","label":"Migration Guide","docId":"migration/massspec-migration","unlisted":false}]},{"type":"category","label":"PyScripts","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/pychron/docs/pyscripts/overview","label":"Overview","docId":"pyscripts/overview","unlisted":false},{"type":"link","href":"/pychron/docs/pyscripts/api-reference","label":"API Reference","docId":"pyscripts/api-reference","unlisted":false}]},{"type":"category","label":"Pipeline","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/pychron/docs/pipeline/data-reduction","label":"Data Reduction","docId":"pipeline/data-reduction","unlisted":false}]},{"type":"category","label":"Deployment","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/pychron/docs/deployment/multi-node","label":"Multi-Node Deployment","docId":"deployment/multi-node","unlisted":false}]},{"type":"category","label":"Dashboard","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/pychron/docs/dashboard/configuration","label":"Configuration","docId":"dashboard/configuration","unlisted":false}]}]},"docs":{"dashboard/configuration":{"id":"dashboard/configuration","title":"Dashboard Configuration","description":"The Pychron dashboard system provides real-time monitoring of laboratory instruments \u2014 vacuum levels, temperatures, laser power, and any other hardware value that a device driver exposes. It consists of:","sidebar":"docsSidebar"},"deployment/multi-node":{"id":"deployment/multi-node","title":"Multi-Node Deployment","description":"A typical Pychron installation spans multiple computers. The acquisition computer runs pyExperiment and connects directly to the spectrometer and extraction line hardware. A valve controller \u2014 often a Raspberry Pi running furPi or a small PC running pyValve \u2014 manages the extraction line solenoid valves. A separate pyCrunch workstation handles data reduction. Each node is its own Pychron application instance; they communicate over TCP RPC and ZMQ publish/subscribe.","sidebar":"docsSidebar"},"dvc/configuration":{"id":"dvc/configuration","title":"Configuration Reference","description":"DVC configuration is split across four preference groups, two git host preference groups, and two environment variables. All preferences are stored in Enthought\'s apptools.preferences system and can be set via the Pychron Preferences UI or by editing ~/.pychron./preferences.ini directly. Fields marked Required will cause DVC to fail silently or with a dialog if missing.","sidebar":"docsSidebar"},"dvc/failure-modes":{"id":"dvc/failure-modes","title":"Failure Modes","description":"DVC has several failure scenarios where the system degrades silently rather than surfacing a clear error. This page documents every known failure mode, its symptom, the responsible code path, and the recovery action.","sidebar":"docsSidebar"},"dvc/first-run":{"id":"dvc/first-run","title":"First-Run Setup","description":"DVC initialization runs automatically every time Pychron starts, triggered by the DVCPlugin startup tests testdatabase and testdvcfetchmeta. Both must pass before any DVC-dependent functionality \u2014 experiment acquisition, pipeline data reduction \u2014 is available. This page walks through setup from scratch, including choosing a git host and database backend.","sidebar":"docsSidebar"},"dvc/offline-mode":{"id":"dvc/offline-mode","title":"Working Offline","description":"Pychron\'s offline mode allows labs to run data reduction without network access to GitHub or GitLab. It works by cloning required repositories to local disk, exporting the central MySQL database to a SQLite file, and reconfiguring DVC to read from those local copies. The tool that orchestrates this is WorkOffline (pychron/dvc/work_offline.py), accessible via Tools \u2192 Work Offline.","sidebar":"docsSidebar"},"dvc/setup-guide":{"id":"dvc/setup-guide","title":"DVC Setup Guide","description":"Pychron DVC (Data Version Control) is a custom git-backed data persistence and provenance system built into Pychron. It is not the open-source dvc.org tool and shares no code or concepts with it. DVC solves the dual challenge of noble gas mass spectrometry data: the catalog of what analyses exist needs fast SQL queries, while the actual measurement data needs full version history, provenance tracking, and reproducible sharing between labs. It accomplishes this by maintaining three storage layers simultaneously.","sidebar":"docsSidebar"},"getting-started/experiment-workflow":{"id":"getting-started/experiment-workflow","title":"Running Your First Experiment","description":"This walkthrough takes you from a fully configured Pychron installation through a complete automated acquisition run and verifies that data was written to DVC. It assumes you have completed the Installation Guide and Quick Start verification steps.","sidebar":"docsSidebar"},"getting-started/installation":{"id":"getting-started/installation","title":"Installation Guide","description":"Pychron now uses uv for Python environment and package management, targeting Python 3.12. If you found an older guide elsewhere, discard it and follow this page.","sidebar":"docsSidebar"},"getting-started/quick-start":{"id":"getting-started/quick-start","title":"Quick Start","description":"This guide walks through the five things to verify on first launch and what to do when something is not green. It assumes Pychron is already installed (uv sync complete, pychron-bootstrap run) and you are ready to launch for the first time.","sidebar":"docsSidebar"},"hardware/compatibility-matrix":{"id":"hardware/compatibility-matrix","title":"Hardware Compatibility Matrix","description":"This matrix covers every hardware category supported by Pychron as of the current main branch. It is derived from a direct audit of pychron/hardware/, pychron/spectrometer/, pychron/lasers/, pychron/furnace/, and related modules. Where limitations exist they are noted inline; see Known Issues at the bottom for items requiring attention before deployment.","sidebar":"docsSidebar"},"hardware/overview":{"id":"hardware/overview","title":"Hardware Overview","description":"Pychron supports a wide range of mass spectrometry laboratory hardware \u2014 spectrometers, lasers, furnaces, vacuum gauges, temperature controllers, motion stages, and more \u2014 through a unified plugin and communicator architecture. Every physical device is represented by a Python driver class, and the communication transport (Serial, Ethernet, GPIB, Modbus, USB) is handled by a separate, swappable Communicator layer. This separation means adding support for a new device rarely requires changes outside its own driver file.","sidebar":"docsSidebar"},"intro":{"id":"intro","title":"Welcome to Pychron","description":"Pychron is an open-source noble gas mass spectrometry platform for Ar-Ar geochronology and thermochronology, developed at the New Mexico Geochronology Research Laboratory (NMGRL) and actively used by more than 12 institutions worldwide. It manages the complete laboratory workflow in a single integrated system: automated extraction line control, CO\u2082 and diode laser operation, resistance furnace management, multi-collector spectrometer acquisition, programmatic scripting of run sequences, git-backed per-analysis data persistence, pipeline-based data reduction, age calculation, and publication-ready output. Pychron is not one application \u2014 it is a suite of specialized apps (pyExperiment, pyCrunch, pyValve, pyLaser, furPi) built on the Enthought plugin framework, each responsible for a distinct part of the workflow and communicating over ZMQ and RPC when deployed across multiple lab computers.","sidebar":"docsSidebar"},"migration/massspec-migration":{"id":"migration/massspec-migration","title":"MassSpec Migration Guide","description":"Step-by-step instructions for migrating a lab from MassSpec to Pychron. See the Migration Overview for architectural differences and strategy options before starting.","sidebar":"docsSidebar"},"migration/massspec-overview":{"id":"migration/massspec-overview","title":"Migrating from MassSpec","description":"MassSpec and Pychron solve the same problem \u2014 automating Ar-Ar geochronology workflows \u2014 but with fundamentally different architectural assumptions. Understanding these differences before planning a migration determines what data can be transferred automatically, what requires manual re-entry, and how day-to-day lab operations will change after the switch.","sidebar":"docsSidebar"},"pipeline/data-reduction":{"id":"pipeline/data-reduction","title":"Data Reduction Walkthrough","description":"This walkthrough covers reducing a set of Ar-Ar analyses in pyCrunch \u2014 from loading a data repository through blank correction, IC factor fitting, age calculation, and exporting a publication-ready age table and ideogram figure. It assumes DVC is configured and at least one experiment has been run and saved.","sidebar":"docsSidebar"},"pyscripts/api-reference":{"id":"pyscripts/api-reference","title":"PyScript API Reference","description":"This page is the complete command reference for Pychron\'s PyScript DSL, compiled from source code in pychron/pyscripts/. Commands are grouped by script type. All commands are Python function calls in plain .py files.","sidebar":"docsSidebar"},"pyscripts/overview":{"id":"pyscripts/overview","title":"PyScripts Overview","description":"PyScripts are Pychron\'s built-in domain-specific language for scripting automated laboratory sequences. Rather than writing general Python, operators write scripts in a constrained vocabulary of commands that map directly to physical laboratory actions \u2014 opening valves, firing lasers, collecting ion beam signals, running peak centers. Scripts are stored as .py files in the MetaRepo and are referenced by name in the experiment queue, ensuring that the exact script used for each analysis is version-controlled alongside the data it produced.","sidebar":"docsSidebar"}}}}')}}]);